                c_start = c
                while c < W and grid[r][c] == 2:
                    c += 1
                c_end = c - 1
                if c_end - c_start + 1 >= 2:
                    h_segments[(r, c_start, c_end)] = False
            else:
                c += 1

    # Map: (r, c) -> segment key, for cells that are 2 and part of a segment
    cell_to_seg = {}
    for (r, c_start, c_end) in h_segments:
        for c in range(c_start, c_end + 1):
            cell_to_seg[(r, c)] = (r, c_start, c_end)

    # Vertical lines to extend: list of (col, start_row)
    # Start with pre-existing 6 positions
    lines = []
    for r in range(H):
        for c in range(W):
            if grid[r][c] == 6:
                lines.append((c, r))

    # Process lines (BFS-like)
    while lines:
        new_lines = []
        for col, start_row in lines:
            for r in range(start_row, H):
                if grid[r][col] == 2:
                    # Blocked by 2 - check if part of a segment
                    seg_key = cell_to_seg.get((r, col))
                    if seg_key and not h_segments[seg_key]:
                        # Activate this segment
                        h_segments[seg_key] = True
